INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-00121', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據原有合法建築物防火避難設施及消防設備改善辦法規定，十一層以上之樓層面積區劃改善規定，下 列敘述何者錯誤？', '["室內牆面及天花板（包括底材）均以耐燃一級材料裝修者，得按每五百平方公尺範圍內，以具有一小 時以上防火時效之牆壁、樓地板及防火設備區劃分隔", "樓地板面積超過一百平方公尺者，應按每一百平方公尺，以具有一小時以上防火時效之牆壁、樓地板 及防火設備區劃分隔", "自地板面起一點二公尺以上之室內牆面及天花板均使用耐燃一級材料裝修者，得按每二百平方公尺， 以具有一小時以上防火時效之牆壁、樓地板及防火設備區劃分隔", "區劃範圍內備有效自動滅火設備者，得免計算其有效範圍樓地板面積之三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00122', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防設備師及消防設備士管理辦法規定，下列敘述何者錯誤？', '["消防設備師（士），自取得證書日起每三年應接受講習一次或取得累計積分達一百六十分以上之訓練 證明文件", "訓練證明文件，指消防設備師（士）參加與消防安全設備設計、監造、裝置及檢修相關之技術研討活 動或訓練取得之積分證明", "消防設備師（士）之獎懲有公開表揚、頒發獎狀或獎牌等方式", "消防設備師（士）拒絕消防機關檢查業務或令其報告之要求時，經限期改善而屆期仍未改善，消防機 關得依行政執行法直接強制方法執行之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00123', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關消防幫浦加壓送水裝置之呼水裝置設置規定，下列何者錯誤？①呼水裝置應有 100 公升以上之有效', '["呼水裝置之補給水管管徑應為15A", "呼水裝置之溢水用排水管管徑50A", "呼水裝置之呼 水管管徑35A  ⑤減水警報裝置及控制盤，均為呼水裝置須具備之機件", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00124', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防幫浦加壓送水裝置等及配管摩擦損失計算基準規定，附屬裝置控制盤之表示燈應易於辨認，有 關表示燈之顏色區分敘述，下列何者錯誤？', '["電源表示燈為白色", "啟動表示燈為紅色", "呼水槽減水表示燈為橘黃色", "電動機電流超過負載表示燈為白色"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00125', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備檢修及申報作業基準規定，火警自動警報設備之局限型感熱型探測器，在有 關執行性能檢查時之檢查注意事項，下列敘述何者錯誤？', '["連接蓄積性能之回路，亦可先行解除其蓄積性能", "設於因水蒸氣滯留而有常時潮濕之虞場所之探測器時，應由差動式局限型試驗器或回路試驗用按鈕等 試驗器進行", "在選出之探測器中，發現有不良品時，應再重新抽選實施檢查", "非再用型探測器每次測試應輪流選取，可於圖面或檢查表上註記每次選取之位置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00126', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防焰性能認證實施要點規定，有關防焰標示方式之敘述下列何者正確？①地毯等地坪舖設物其標示', '["窗簾具耐洗性能者，其標示方式採縫製或鑲釘方式", "施工用帆布其標示方 式採張貼方式", "布幕不具耐洗性能者，其標示方式採縫製方式  ⑤展示用廣告板，其標示方式採懸掛 ⑥防焰材料（合板除外），其標示方式採張貼或懸掛", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00127', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據原有合法建築物防火避難設施及消防設備改善辦法之規定，針對原有合法建築物之敘述，何者 錯誤？', '["原有合法建築物垂直區劃之電扶梯及昇降機間部分，應以具有一小時以上防火時效之牆壁、防火 設備與該處防火構造之樓地板形成區劃分隔", "防火構造建築物之樓地板應為連續完整面，並應突出建築物外牆五十公分以上", "高層建築物設有防災中心者，該防災中心應以具有一小時以上防火時效之牆壁、防火設備及該層 防火構造之樓地板予以區劃分隔", "避難層以外樓層之出入口寬度不得小於九十公分，高度不得低於一點八公尺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00128', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據建築技術規則規定，針對安全梯之敘述，何者錯誤？', '["室內安全梯間四周牆壁應具有一小時以上防火時效", "進入室內安全梯之出入口其寬度不得小於九十公分", "特別安全梯樓梯間及排煙室其天花板及牆面之裝修，應為耐燃一級材料", "戶外安全梯之出入口應裝設具有半小時以上防火時效且具有半小時以上阻熱性之防火門"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00129', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，有關二氧化碳滅火設備何者敘述為錯誤？', '["二氧化碳滅火設備之放射方式採移動放射方式，其皮管接頭至防護對象任一部分之水平距離在 十五公尺以下", "低壓式儲存容器應設置使容器內部溫度維持於攝氏零下二十度以上，攝氏零下十八度以下之自動 冷凍機", "二氧化碳噴頭之放射壓力，其滅火藥劑以常溫儲存者之高壓式為每平方公分十二公斤以上", "啟動用氣體容器之內容積應有一公升以上，其所儲存之二氧化碳重量在零點六公斤以上，且其充 填比在一點五以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00130', 'fire-eq-eng', 'fire-eq-eng-moex-101-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，有關公共危險物品等場所消防設計及消防安全設備之 敘述何者為錯誤？', '["第三種滅火設備係指水霧、泡沫、二氧化碳或乾粉滅火設備", "公共危險物品儲存場所之建築物，外牆為防火構造，設置第五種滅火設備者，總樓地板面積每 一百平方公尺（含未滿）有一滅火效能值", "電氣設備使用之處所，每一百平方公尺（含未滿）應設置第五種滅火設備一具以上", "室內消防栓設備之緊急電源，其供電容量應供其有效動作四十五分鐘以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
